args.sparql:
SELECT ?author ?authorLabel ?novelName 
WHERE {
  ?series wdt:P31 wd:Q734449;
          wdt:P128 wd:Q725100;
          wdt:P577 ?date;
          wdt:P1544 ?themeSong;
          wdt:P1469 ?novel.
  ?themeSong wdt:P175 wd:Q714449.
  ?novel wdt:P50 ?author.
  FILTER (YEAR(?date) = 1999).
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
  ?author rdfs:label ?authorLabel.
  ?novel rdfs:label ?novelName.
}

SELECT DISTINCT ?author ?authorLabel ?novelName 
WHERE {
  ?series wdt:P31 wd:Q734449;
          wdt:P577 ?airDate;
          wdt:P1544 ?themeSong;
          wdt:P1469 ?novel.
  ?themeSong wdt:P175 wd:Q714449.
  ?novel wdt:P50 ?author.
  FILTER (YEAR(?airDate) = 1999).
  ?author rdfs:label ?authorLabel.
  ?novel rdfs:label ?novelName.
  FILTER (LANG(?authorLabel) = "en").
  FILTER (LANG(?novelName) = "en").
}
